sql:
SELECT hospital_name, SUBSTR(hospital_name, 1, 3) AS first_three_chars
FROM hospitals
WHERE hospital_id > 5;

SELECT hospital_id, SUM(bed_count) AS Total_Beds
FROM icu_units
GROUP BY hospital_id;

SELECT location, COUNT(hospital_id) AS number_of_hospitals
FROM hospitals
GROUP BY location;

external_knowledge:
- In this metaphor, hospitals are likened to lighthouses guiding ships (patients) safely to their bays (admission);
- "Admitted" indicates that the patients are currently in the hospital and have not been discharged or transferred;
- "New York" refers to the location of the hospitals.

sql:
SELECT SUM(total_cost) AS total_cost
FROM resource_utilization
WHERE date BETWEEN datetime('now', '-30 days') AND datetime('now');

SELECT hospital_name 
FROM hospitals 
ORDER BY hospital_name ASC;
